// Función para convertir cualquier formato de fecha a número comparable
function dateToComparableNumber(value) {
  // Si es null o undefined
  if (!value) return 0;

  // Si ya es un número (serial de Excel/Google Sheets)
  if (typeof value === 'number') {
    return value;
  }

  // Si es string
  if (typeof value === 'string') {
    // Verificar si es un número en formato string (con coma o punto)
    const numericString = value.replace(',', '.');
    if (!isNaN(numericString) && numericString.trim() !== '') {
      return parseFloat(numericString);
    }

    // Si es fecha en formato DD/MM/YYYY HH:MM:SS
    if (value.includes('/')) {
      try {
        const [datePart, timePart = "00:00:00"] = value.trim().split(' ');
        const [day, month, year] = datePart.split('/').map(n => parseInt(n, 10));
        const [hour = 0, minute = 0, second = 0] = timePart.split(':').map(n => parseInt(n, 10));

        // Convertir a fecha JavaScript
        const date = new Date(year, month - 1, day, hour, minute, second);

        // Convertir fecha a número serial de Excel
        const excelEpoch = new Date(1899, 11, 30);
        const msPerDay = 24 * 60 * 60 * 1000;
        const excelSerial = (date.getTime() - excelEpoch.getTime()) / msPerDay;

        return excelSerial;
      } catch (e) {
        console.log(`Error parsing date "${value}":`, e.message);
        return 0;
      }
    }
  }

  // Si es un objeto Date
  if (value instanceof Date) {
    const excelEpoch = new Date(1899, 11, 30);
    const msPerDay = 24 * 60 * 60 * 1000;
    return (value.getTime() - excelEpoch.getTime()) / msPerDay;
  }

  return 0;
}

// Procesar todos los items para comparación
const processedItems = items.map((item, index) => {
  const rawValue = item.json["Marca temporal"];
  const comparableValue = dateToComparableNumber(rawValue);

  console.log(`Item ${index}: Marca temporal="${rawValue}" → Valor comparable=${comparableValue.toFixed(8)}`);

  return {
    item: item,
    comparableValue: comparableValue,
    index: index
  };
});

// Encontrar el máximo
let maxEntry = processedItems[0];
processedItems.forEach(entry => {
  if (entry.comparableValue > maxEntry.comparableValue) {
    maxEntry = entry;
  }
});

// Mostrar información del registro seleccionado
console.log("\n=== REGISTRO MÁS RECIENTE ===");
console.log("Marca temporal:", maxEntry.item.json["Marca temporal"]);
console.log("Valor numérico:", maxEntry.comparableValue.toFixed(8));
console.log("Total de columnas en el registro:", Object.keys(maxEntry.item.json).length);

// Mostrar algunas columnas clave para verificación
console.log("\nAlgunas columnas del registro seleccionado:");
console.log("- ID:", maxEntry.item.json["ID LABEL (Don´t touch)"]);
console.log("- Room:", maxEntry.item.json["ROOM NUMBER / Nº HABITACIÓN"]);
console.log("- First Name:", maxEntry.item.json["Your First Name"]);
console.log("- Check IN:", maxEntry.item.json["Fecha inicio contrato (Check IN)"]);
console.log("- Check OUT:", maxEntry.item.json["Fecha fin contrato (Check Out)"]);

// IMPORTANTE: Devolver el item COMPLETO con TODAS sus columnas
return [maxEntry.item];

